-- Enrichment marathon batch: OpenZiti, Operational.co, Opinion Stage, OpnForm, OpsLevel, Optimizely, OpusClip, OrangeHRM

-- ── OpenZiti ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenZiti is a free, open-source zero-trust networking platform that lets developers embed secure, identity-based overlay networking directly into applications, making services invisible to unauthorized users.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Charlotte, North Carolina, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenZiti Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenZiti review: open-source zero-trust networking overlay with SDKs and tunnelers. See features, self-hosting vs NetFoundry Cloud pricing, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenZiti is a fully open-source (Apache 2.0) zero-trust networking platform that lets developers and network engineers embed secure, identity-based overlay networking directly into applications and infrastructure. Rather than exposing services on the public internet or a traditional VPN, OpenZiti makes network services invisible by default: every connection from a user, service, device, or workload must be authenticated with cryptographic identity, authorized by policy, and encrypted end-to-end before a network path is even established. The project was created and is primarily sponsored by NetFoundry, a networking company founded in 2017 and headquartered in Charlotte, North Carolina, which also sells a commercial managed cloud service (NetFoundry Cloud for OpenZiti) built on top of the same open-source core. OpenZiti supports two integration models: a zero-code path using lightweight tunnelers/appliances that work with existing applications, and an embedded path using native SDKs (Go, C, Swift, Java/Kotlin, C#, NodeJS) for applications that want the strongest zero-trust guarantees baked in at the code level. Core components include the Ziti controller, edge routers, a policy engine, and a browser-based admin console (ZAC). Because it is self-hostable and Apache 2.0 licensed, OpenZiti itself is entirely free to run; NetFoundry monetizes through a managed cloud offering (with a free trial including up to 10 endpoints and 1 TB of data) and enterprise support contracts, both quoted on request rather than published. Target users are network engineers, platform/security teams, and application developers who need to replace traditional VPNs, firewalls, and bastion hosts with a modern, application-embedded zero-trust architecture — particularly for remote access, multi-cloud connectivity, IoT/edge device networking, and securing legacy applications without exposing open ports. Its closest comparisons are other zero-trust network access (ZTNA) and secure overlay tools such as Tailscale, Cloudflare Zero Trust/Access, Twingate, and Zscaler Private Access, though OpenZiti differentiates itself by being fully open source, self-hostable end-to-end, and designed to be programmable and embeddable inside applications rather than just a network appliance. It is used in production by NetFoundry's own internal and external systems and by organizations building zero-trust remote access, secure IoT connectivity, and dark/invisible service architectures.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1dbc0d6c-8ba8-4f49-aeb1-c6dcd71d5cfe';

