-- ── OpnForm ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpnForm is an open-source, no-code form builder offering unlimited forms and responses, positioned as a Typeform and JotForm alternative for individuals, startups, and enterprises.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; Pro from $25/month$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Remote / not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpnForm Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpnForm review: open-source form builder with unlimited responses. Compare features, self-hosted vs cloud pricing, and alternatives like Typeform.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpnForm is an open-source, no-code form builder positioned as an alternative to Typeform, JotForm, and Tally, built on Laravel, Vue.js, and TailwindCSS. It was created by developer Julien Nahum, who first built a related Notion-integrated form tool (NotionForms, later rebranded and expanded) that grew to roughly $200k ARR as a largely solo, bootstrapped project before evolving into the standalone OpnForm product, publicly launched around 2023 and later promoted via an AppSumo lifetime-deal campaign. The product's central pitch is a genuinely generous free tier: unlimited forms and unlimited submissions on the hosted cloud plan at no cost, with the only real limitations being OpnForm branding and no custom domain support, a stance most direct competitors don't match since they typically cap monthly responses. OpnForm supports a drag-and-drop builder with multi-step layouts, conditional logic, computed fields, both 'classic' and Typeform-style conversational form styles, and distribution via direct links, embeds, custom domains, Notion integration, and QR codes, alongside native integrations for Slack, Discord, Google Sheets, Zapier, Stripe, webhooks, and a REST API. It reports over 10,000 companies using the platform and more than 3,500 stars on its GitHub repository (OpnForm/OpnForm), with visible customers including Berkeley, the UN, Vanguard, and Zomato. Because the core is licensed AGPL-3.0, OpnForm is also fully self-hostable at no cost via a Community Edition (capped at 2 users, with OIDC SSO and community support), while advanced enterprise capabilities are gated behind a separate Enterprise License for self-hosters, priced at $1,999/year per instance. On the hosted cloud side, pricing runs Free, Pro (roughly $25-29/month, or 15% less billed yearly) which adds branding removal, custom domains, custom SMTP, chat-app notifications, password-protected forms, analytics, and AI form generation; Business (roughly $67-79/month) which adds multi-user roles and permissions, advanced branding, larger file uploads, and priority support; and Enterprise (roughly $220-250/month) which adds SAML/LDAP SSO, audit logs, external storage, white-label hosting, and SLA-backed onboarding. OpnForm targets indie developers, startups, and cost-conscious teams who want Typeform-quality forms without response-based pricing, and it also offers an EU-hosted infrastructure option for organizations with data-residency requirements, competing most directly with Typeform, JotForm, Tally, and other open-source form builders.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'acb31b58-aa23-4c6b-b191-585512bf65f6';

