-- ── Optimizely ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Optimizely is a major digital experience platform combining content management, A/B testing and experimentation, personalization, and commerce tools, formed when Episerver acquired and rebranded around the original Optimizely testing company.$q$, short_description),
  pricing_model = COALESCE($q$Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom quote$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$1,000-1,700 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$Swedish$q$, $q$French$q$, $q$Spanish$q$, $q$and other localized editions$q$]::text[],
  seo_title = COALESCE($q$Optimizely Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Optimizely review: enterprise CMS, A/B testing, personalization, and commerce platform. See features, custom pricing, company history, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Optimizely is a major enterprise digital experience platform (DXP) that combines content management, A/B testing and experimentation, personalization, commerce, and analytics into a single suite. Its origins trace to two separate companies: Episerver, a content management company founded in 1994 in Stockholm, Sweden by Mikael Runhem, and the original Optimizely, an A/B testing and experimentation company founded in 2010 in San Francisco by Dan Siroker and Pete Koomen (both former Google employees). In September 2018, Episerver was acquired by growth equity firm Insight Partners for approximately $1.16 billion; in October 2020, Insight-backed Episerver acquired Optimizely, and in January 2021 the combined company rebranded entirely under the Optimizely name, retiring the Episerver brand. Optimizely remains a privately held, Insight Partners-backed company today, headquartered in San Francisco, California, with additional major offices and roughly 1,000-1,700 employees globally (estimates vary by data source). The current Optimizely product suite spans a Content Marketing Platform (CMS), Experimentation (server-side and client-side A/B/multivariate testing, feature flagging), Personalization, Commerce, Data Platform, Asset Management, and increasingly AI-driven 'Agentic CMS' and 'Agentic Experimentation' capabilities announced as the company leans into AI-assisted content and testing workflows. Optimizely serves large and mid-market enterprises, particularly marketing, e-commerce, and digital product teams that need to manage content, run structured experiments, and personalize experiences across web and app at scale. The company does not publish self-serve pricing; every plan is individually packaged based on a prospect's specific digital needs, requiring a sales conversation to get a quote, which is typical for enterprise DXP vendors. Its main competitors include Adobe Experience Manager and Adobe Target, Sitecore, Contentful, VWO, AB Tasty, and Salesforce Commerce Cloud, with Optimizely's differentiation resting on its combination of experimentation heritage (from the original Optimizely) with Episerver's enterprise CMS and commerce depth, giving it a broader, more integrated DXP suite than pure-play testing tools while retaining deep experimentation capability that many CMS-first competitors lack.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5de91ee1-beae-41ba-afc9-53772c7393cb';

